```Cargo.toml
[package]
name = "gce-vm"
version = "1.0.6"
edition = "2021"
authors = ["Rodolfo Villaruz <rodolfo@yes.ph>"]
description = "A small command-line tool for managing a single Google Compute Engine VM you use as a development or work machine."
license = "MIT"
repository = "https://github.com/rodolfovillaruz/gvm"
readme = "README.md"
keywords = ["cli", "tool"]
categories = ["command-line-utilities"]
exclude = [
    ".dump/*"
]

[[bin]]
name = "gvm"
path = "src/main.rs"

[dependencies]
tokio       = { version = "1", features = ["full"] }
clap        = { version = "4", features = ["derive", "env"] }
anyhow      = "1"
thiserror   = "2"
reqwest     = { version = "0.13", features = ["json", "rustls"] }
serde       = { version = "1",    features = ["derive"] }
serde_json  = "1"
gcp_auth    = "0.12"
colored     = "3"
google-cloud-auth = "1.9.0"
google-cloud-compute-v1 = "2.4.0"
google-cloud-gax = "1.9.1"

```

```src/main.rs
...
    match subcommand.as_str() {
        "status" => {
            let simple = if status == "RUNNING" {
                "RUNNING"
            } else {
                "STOPPED"
            };
            println!("{simple}");
            Ok(())
        }

        "ssh" => {
            // GVM_USER is required for ssh.
            let user = require_gvm_user()?;

            let ip = ip
                .ok_or_else(|| format!("instance `{instance_name}` has no reachable IP address"))?;

            eprintln!(
                "\x1b[32mConnecting\x1b[0m to {user}@{ip} \
                 (instance `{instance_name}` in zone {zone})"
            );

            let status = Command::new("ssh")
                .arg("-o")
                .arg("StrictHostKeyChecking=no")
                .arg("-o")
                .arg("UserKnownHostsFile=/dev/null")
                .arg(format!("{user}@{ip}"))
                .args(&rest)
                .status()?;

            std::process::exit(status.code().unwrap_or(1));
        }

        "tmux" => {
            let user = require_gvm_user()?;

            // The first positional argument after "tmux" is the session name.
            let session_name = rest.first().ok_or_else(|| {
                eprintln!("\x1b[31mError:\x1b[0m Usage: {program} tmux <session-name>");
                "missing session-name"
            })?;

            if status != "RUNNING" {
                return Err(format!(
                    "instance `{instance_name}` is not running (status: {status}). \
                     Use `{program} start` to start it first."
                )
                .into());
            }

            let ip = ip
                .ok_or_else(|| format!("instance `{instance_name}` has no reachable IP address"))?;

            eprintln!(
                "\x1b[32mConnecting\x1b[0m to {user}@{ip} \
                 (instance `{instance_name}` in zone {zone}, tmux session `{session_name}`)"
            );

            // -t allocates a pseudo-TTY, which tmux requires.
            let exit_status = Command::new("ssh")
                .arg("-t")
                .arg(format!("{user}@{ip}"))
                .arg(format!("tmux new -As {session_name}"))
                .status()?;

            std::process::exit(exit_status.code().unwrap_or(1));
        }

        "start" => {
            if status == "RUNNING" {
                eprintln!("Instance `{instance_name}` is already RUNNING.");
            } else {
                eprintln!(
                    "\x1b[32mStarting\x1b[0m instance `{instance_name}` in zone {zone} \
                     (current status: {status})..."
                );
                client
                    .start()
                    .set_project(project_id.clone())
                    .set_zone(zone.clone())
                    .set_instance(instance_name.clone())
                    .send()
                    .await?;
            }

            let timeout_secs: u64 = std::env::var("GVM_START_TIMEOUT")
                .ok()
                .and_then(|s| s.parse().ok())
                .unwrap_or(180);

            wait_for_ssh(
                &client,
                &project_id,
                &zone,
                &instance_name,
                Duration::from_secs(timeout_secs),
            )
            .await?;

            std::process::exit(0);
        }

        other => {
            eprintln!(
                "Unknown subcommand `{other}`. \
                 Usage: {program} <start|status|ssh|tmux> [args...]"
            );
            Err(format!("unknown subcommand: {other}").into())
        }
    }
}
